using System; using System.Collections.Generic; using System.Drawing; using System.Windows.Forms; namespace btlwindow { public partial class ucManageMembers : UserControl { public ucManageMembers() { InitializeComponent(); } private void ucManageMembers_Load(object sender, EventArgs e) { LoadMembers(); } public void LoadMembers() { dgvMembers.Rows.Clear(); List<MemberModel> members = MemberRepository.GetAllMembers(); foreach (var m in members) { int idx = dgvMembers.Rows.Add(m.Id, m.HoTen, m.Email, m.Role, m.NgayTao.ToString("dd/MM/yyyy")); dgvMembers.Rows[idx].Tag = m; } } private void btnChangeRole_Click(object sender, EventArgs e) { if (dgvMembers.SelectedRows.Count == 0) { MessageBox.Show("Vui long chon thanh vien!"); return; } MemberModel m = dgvMembers.SelectedRows[0].Tag as MemberModel; if (m == null) return; string newRole = m.Role == "Manager" ? "Employee" : "Manager"; if (MemberRepository.UpdateMemberRole(m.Id, newRole)) { LoadMembers(); MessageBox.Show("Da cap nhat role thanh cong!"); } } private void btnDelete_Click(object sender, EventArgs e) { if (dgvMembers.SelectedRows.Count == 0) { MessageBox.Show("Vui long chon thanh vien!"); return; } MemberModel m = dgvMembers.SelectedRows[0].Tag as MemberModel; if (m == null) return; if (m.Id == CurrentUser.User.Id) { MessageBox.Show("Khong the xoa chinh minh!"); return; } if (MessageBox.Show("Ban co chac muon xoa thanh vien nay?", "Xac nhan", MessageBoxButtons.YesNo) == DialogResult.Yes) { if (MemberRepository.DeleteMember(m.Id)) { LoadMembers(); } } } } }